// BrandReveal.tsx — Logo + brand colors animation

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Building2 } from 'lucide-react';

interface BrandRevealProps {
  logo: string | null;
  colors: string[];
  companyName: string | null;
  isRevealed: boolean;
}

export const BrandReveal: React.FC<BrandRevealProps> = ({
  logo,
  colors,
  companyName,
  isRevealed
}) => {
  const [logoPhase, setLogoPhase] = useState<'center' | 'corner'>('center');

  // Transition logo to corner after reveal
  useEffect(() => {
    if (isRevealed && logo) {
      const timer = setTimeout(() => setLogoPhase('corner'), 2000);
      return () => clearTimeout(timer);
    }
  }, [isRevealed, logo]);

  return (
    <div className="relative">
      {/* Centered Logo (initial reveal) */}
      <AnimatePresence>
        {logo && logoPhase === 'center' && (
          <motion.div
            className="fixed inset-0 flex items-center justify-center z-50 pointer-events-none"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0, scale: 0.5 }}
            transition={{ duration: 0.5 }}
          >
            <motion.div
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ 
                type: 'spring', 
                stiffness: 200, 
                damping: 20,
                delay: 0.2 
              }}
              className="relative"
            >
              {/* Glow effect */}
              <div className="absolute inset-0 blur-3xl bg-gradient-to-r from-cyan-500/30 to-emerald-500/30 scale-150" />
              <img 
                src={logo} 
                alt="Company Logo"
                className="w-48 h-48 object-contain relative z-10"
              />
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Corner Logo (after transition) */}
      <AnimatePresence>
        {logo && logoPhase === 'corner' && (
          <motion.div
            className="flex items-center gap-4"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5 }}
          >
            <motion.img
              src={logo}
              alt="Company Logo"
              className="w-12 h-12 object-contain rounded-lg bg-white/10 p-2"
              layoutId="company-logo"
            />
            {companyName && (
              <motion.h2
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2 }}
                className="text-xl font-semibold text-white"
              >
                {companyName}
              </motion.h2>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Placeholder when no logo yet */}
      {!logo && (
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-lg bg-white/5 flex items-center justify-center">
            <Building2 className="w-6 h-6 text-white/30" />
          </div>
          <div className="h-6 w-32 bg-white/5 rounded animate-pulse" />
        </div>
      )}

      {/* Brand Colors */}
      <AnimatePresence>
        {colors.length > 0 && (
          <motion.div
            className="flex items-center gap-2 mt-4"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
          >
            <span className="text-xs text-white/40 mr-2">Brand Colors</span>
            {colors.map((color, index) => (
              <motion.div
                key={`${color}-${index}`}
                initial={{ scale: 0, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ 
                  delay: index * 0.1,
                  type: 'spring',
                  stiffness: 300 
                }}
                className="relative group"
              >
                <div
                  className="w-8 h-8 rounded-full border-2 border-white/20 shadow-lg cursor-pointer transition-transform hover:scale-110"
                  style={{ backgroundColor: color }}
                  title={color}
                />
                {/* Color hex tooltip */}
                <motion.div
                  className="absolute -bottom-8 left-1/2 -translate-x-1/2 px-2 py-1 bg-black/80 rounded text-[10px] text-white/70 font-mono opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap"
                >
                  {color}
                </motion.div>
              </motion.div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default BrandReveal;
