// TaskCreationFeed.tsx — Right sidebar showing auto-created tasks

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  CheckSquare, 
  ArrowRight, 
  Users,
  Sparkles,
  Clock
} from 'lucide-react';

export interface AutoTask {
  id: string;
  title: string;
  department: string;
  priority: 'low' | 'medium' | 'high';
  createdAt: Date;
}

interface TaskCreationFeedProps {
  tasks: AutoTask[];
}

const priorityColors = {
  low: 'bg-slate-500/20 text-slate-400 border-slate-500/30',
  medium: 'bg-amber-500/20 text-amber-400 border-amber-500/30',
  high: 'bg-rose-500/20 text-rose-400 border-rose-500/30',
};

const departmentColors: Record<string, string> = {
  Content: 'text-purple-400',
  Marketing: 'text-pink-400',
  Research: 'text-cyan-400',
  Analytics: 'text-emerald-400',
  Sales: 'text-amber-400',
  Support: 'text-blue-400',
  default: 'text-white/60',
};

export const TaskCreationFeed: React.FC<TaskCreationFeedProps> = ({
  tasks
}) => {
  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 pb-3 border-b border-white/10">
        <h3 className="text-sm font-medium text-white/80 flex items-center gap-2">
          <Sparkles className="w-4 h-4 text-violet-400" />
          Auto-Generated Tasks
        </h3>
        <motion.div
          key={tasks.length}
          initial={{ scale: 1.2 }}
          animate={{ scale: 1 }}
          className="px-2 py-0.5 bg-violet-500/20 rounded text-xs text-violet-400"
        >
          {tasks.length}
        </motion.div>
      </div>

      {/* Task List */}
      <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
        <AnimatePresence mode="popLayout" initial={false}>
          {tasks.map((task, index) => (
            <motion.div
              key={task.id}
              layout
              initial={{ opacity: 0, x: 50, scale: 0.9 }}
              animate={{ opacity: 1, x: 0, scale: 1 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{
                type: 'spring',
                stiffness: 400,
                damping: 25,
                delay: index * 0.05
              }}
              className="bg-white/5 rounded-lg border border-white/10 p-3 hover:bg-white/10 transition-colors"
            >
              {/* Task Header */}
              <div className="flex items-start gap-2 mb-2">
                <CheckSquare className="w-4 h-4 text-violet-400 mt-0.5 flex-shrink-0" />
                <p className="text-sm text-white/90 leading-tight flex-1">
                  {task.title}
                </p>
              </div>

              {/* Task Meta */}
              <div className="flex items-center justify-between ml-6">
                {/* Department */}
                <div className="flex items-center gap-1.5 text-xs">
                  <ArrowRight className="w-3 h-3 text-white/30" />
                  <Users className="w-3 h-3 text-white/30" />
                  <span className={departmentColors[task.department] || departmentColors.default}>
                    {task.department}
                  </span>
                </div>

                {/* Priority Badge */}
                <span className={`px-2 py-0.5 rounded text-[10px] border ${priorityColors[task.priority]}`}>
                  {task.priority}
                </span>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {/* Empty State */}
        {tasks.length === 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-center py-8"
          >
            <Clock className="w-8 h-8 text-white/20 mx-auto mb-2" />
            <p className="text-sm text-white/30">
              Tasks will appear as<br />findings are analyzed
            </p>
          </motion.div>
        )}
      </div>

      {/* Footer Summary */}
      {tasks.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mt-4 pt-3 border-t border-white/10"
        >
          <div className="flex items-center justify-between text-xs text-white/40">
            <span>
              {tasks.filter(t => t.priority === 'high').length} high priority
            </span>
            <span>
              {new Set(tasks.map(t => t.department)).size} departments
            </span>
          </div>
        </motion.div>
      )}
    </div>
  );
};

export default TaskCreationFeed;
