// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Get template by ID
 */
export function getOnboardingTemplate(id: string): DepartmentOnboardingTemplate | undefined {
  return ONBOARDING_TEMPLATES.find(t => t.id === id);
}

/**
 * Get default AI specialist for a template
 */
export function getDefaultAI(templateId: string) {
  const template = getOnboardingTemplate(templateId);
  return template?.aiSpecialists.find(ai => ai.recommended);
}

/**
 * Calculate context score from progress
 */
export function calculateContextScore(
  progress: OnboardingProgress, 
  template: DepartmentOnboardingTemplate
): number {
  const totalSteps = template.onboardingSteps.length;
  if (totalSteps === 0) return 100;
  
  const completedSteps = Object.values(progress).filter(Boolean).length;
  return Math.round((completedSteps / totalSteps) * 100);
}

/**
 * Get all available template IDs
 */
export function getTemplateIds(): string[] {
  return ONBOARDING_TEMPLATES.map(t => t.id);
}
