// FindingsFeed.tsx — Real-time findings ticker at bottom

import React, { useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Instagram, 
  Facebook, 
  Twitter, 
  Linkedin, 
  Youtube,
  ShoppingCart,
  Globe,
  Mail,
  Phone,
  MapPin,
  FileText,
  Code,
  Zap,
  CheckCircle2,
  Link2
} from 'lucide-react';

export interface Finding {
  id: string;
  type: string;
  message: string;
  timestamp: Date;
  data?: any;
}

interface FindingsFeedProps {
  findings: Finding[];
  maxDisplay?: number;
}

const getIcon = (type: string) => {
  const iconMap: Record<string, React.ReactNode> = {
    instagram: <Instagram className="w-4 h-4 text-pink-400" />,
    facebook: <Facebook className="w-4 h-4 text-blue-400" />,
    twitter: <Twitter className="w-4 h-4 text-sky-400" />,
    linkedin: <Linkedin className="w-4 h-4 text-blue-500" />,
    youtube: <Youtube className="w-4 h-4 text-red-400" />,
    shopify: <ShoppingCart className="w-4 h-4 text-green-400" />,
    woocommerce: <ShoppingCart className="w-4 h-4 text-purple-400" />,
    tech: <Code className="w-4 h-4 text-cyan-400" />,
    email: <Mail className="w-4 h-4 text-amber-400" />,
    phone: <Phone className="w-4 h-4 text-emerald-400" />,
    address: <MapPin className="w-4 h-4 text-rose-400" />,
    page: <FileText className="w-4 h-4 text-white/50" />,
    social: <Link2 className="w-4 h-4 text-violet-400" />,
    default: <Zap className="w-4 h-4 text-yellow-400" />,
  };
  return iconMap[type.toLowerCase()] || iconMap.default;
};

export const FindingsFeed: React.FC<FindingsFeedProps> = ({
  findings,
  maxDisplay = 5
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const displayFindings = findings.slice(-maxDisplay).reverse();

  // Auto-scroll to show new findings
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = 0;
    }
  }, [findings.length]);

  return (
    <div className="w-full">
      {/* Header */}
      <div className="flex items-center justify-between mb-3">
        <h3 className="text-sm font-medium text-white/60 flex items-center gap-2">
          <Zap className="w-4 h-4 text-yellow-400" />
          Live Discoveries
        </h3>
        {findings.length > 0 && (
          <motion.div
            key={findings.length}
            initial={{ scale: 1.2 }}
            animate={{ scale: 1 }}
            className="flex items-center gap-1 text-xs text-white/40"
          >
            <CheckCircle2 className="w-3 h-3 text-emerald-400" />
            {findings.length} found
          </motion.div>
        )}
      </div>

      {/* Findings List */}
      <div 
        ref={containerRef}
        className="space-y-2 max-h-48 overflow-hidden"
      >
        <AnimatePresence mode="popLayout" initial={false}>
          {displayFindings.map((finding, index) => (
            <motion.div
              key={finding.id}
              layout
              initial={{ opacity: 0, x: -20, height: 0 }}
              animate={{ opacity: 1, x: 0, height: 'auto' }}
              exit={{ opacity: 0, x: 20, height: 0 }}
              transition={{
                type: 'spring',
                stiffness: 500,
                damping: 30,
                opacity: { duration: 0.2 }
              }}
              className="flex items-center gap-3 px-3 py-2 bg-white/5 rounded-lg border border-white/10"
            >
              {/* Icon */}
              <div className="flex-shrink-0">
                {getIcon(finding.type)}
              </div>

              {/* Message */}
              <p className="text-sm text-white/80 flex-1 truncate">
                {finding.message}
              </p>

              {/* Timestamp */}
              <span className="text-[10px] text-white/30 flex-shrink-0">
                just now
              </span>

              {/* New indicator */}
              {index === 0 && (
                <motion.div
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  className="w-2 h-2 bg-cyan-400 rounded-full"
                />
              )}
            </motion.div>
          ))}
        </AnimatePresence>

        {/* Empty state */}
        {findings.length === 0 && (
          <div className="text-center py-4">
            <motion.div
              animate={{ opacity: [0.3, 0.6, 0.3] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="text-white/30 text-sm"
            >
              Scanning website...
            </motion.div>
          </div>
        )}
      </div>
    </div>
  );
};

export default FindingsFeed;
