// CrawlTheater.tsx — Main container for visual crawl experience

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';

import { CrawlProgress } from './CrawlProgress';
import { BrandReveal } from './BrandReveal';
import { ProductGrid, Product } from './ProductGrid';
import { FindingsFeed, Finding } from './FindingsFeed';
import { TaskCreationFeed, AutoTask } from './TaskCreationFeed';
import { ApprovalGate } from './ApprovalGate';

// Get API base from environment or default
const API_BASE = import.meta.env.VITE_API_URL || 'https://ienable-admin-app-hqtw2.ondigitalocean.app/api/v1';

interface CrawlTheaterProps {
  url: string;
  onComplete?: (data: CrawlResult) => void;
  onClose?: () => void;
}

export interface CrawlResult {
  jobId: string;
  companyName: string | null;
  logo: string | null;
  colors: string[];
  products: Product[];
  findings: Finding[];
  tasks: AutoTask[];
}

export const CrawlTheater: React.FC<CrawlTheaterProps> = ({
  url,
  onComplete,
  onClose
}) => {
  // Crawl state
  const [jobId, setJobId] = useState<string | null>(null);
  const [status, setStatus] = useState<'starting' | 'crawling' | 'complete' | 'error'>('starting');
  const [error, setError] = useState<string | null>(null);
  
  // Progress state
  const [currentUrl, setCurrentUrl] = useState<string>('');
  const [pagesDiscovered, setPagesDiscovered] = useState(0);
  const [progress, setProgress] = useState(0);
  
  // Data state
  const [logo, setLogo] = useState<string | null>(null);
  const [colors, setColors] = useState<string[]>([]);
  const [companyName, setCompanyName] = useState<string | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [findings, setFindings] = useState<Finding[]>([]);
  const [tasks, setTasks] = useState<AutoTask[]>([]);
  
  // UI state
  const [isRevealed, setIsRevealed] = useState(false);
  const [isReady, setIsReady] = useState(false);
  const [isApproving, setIsApproving] = useState(false);

  // Start the crawl
  useEffect(() => {
    const startCrawl = async () => {
      try {
        setCurrentUrl(url);
        const response = await fetch(`${API_BASE}/onboarding/crawl`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url })
        });
        
        if (!response.ok) {
          throw new Error('Failed to start crawl');
        }
        
        const result = await response.json();
        setJobId(result.data?.job_id || result.jobId || result.id);
        setStatus('crawling');
      } catch (err) {
        console.error('Failed to start crawl:', err);
        setError('Failed to start crawl. Please try again.');
        setStatus('error');
      }
    };

    if (url) {
      startCrawl();
    }
  }, [url]);

  // Connect to SSE stream
  useEffect(() => {
    if (!jobId) return;

    const eventSource = new EventSource(`${API_BASE}/onboarding/crawl/${jobId}/stream`);
    
    let receivedData = false;
    const findingQueue: any[] = [];
    let isProcessing = false;
    
    // Dramatic pacing: release findings one by one with delays
    const processQueue = async () => {
      if (isProcessing) return;
      isProcessing = true;
      while (findingQueue.length > 0) {
        const data = findingQueue.shift()!;
        
        // Check if this is the completion event
        if (data.type === 'complete' || (data.type === 'status' && data.data?.status === 'completed')) {
          // Wait a beat before showing completion
          await new Promise(r => setTimeout(r, 1500));
          setStatus('complete');
          setIsReady(true);
          isProcessing = false;
          return;
        }
        
        handleFinding(data);
        
        // Dramatic delays based on finding type
        const delays: Record<string, number> = {
          status: 500,
          company_name: 1200,
          logo: 1500,
          colors: 1200,
          tagline: 800,
          tech_stack: 1000,
          social_links: 800,
          pages: 600,
          product: 400,
          connected: 300,
        };
        const delay = delays[data.type] || 600;
        await new Promise(r => setTimeout(r, delay));
      }
      isProcessing = false;
    };
    
    eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        receivedData = true;
        findingQueue.push(data);
        processQueue();
      } catch (err) {
        console.error('Failed to parse SSE message:', err);
      }
    };

    eventSource.onerror = () => {
      eventSource.close();
      // If we received data, let the queue finish naturally
      if (receivedData && findingQueue.length === 0 && !isProcessing) {
        setStatus('complete');
        setIsReady(true);
      }
    };

    return () => {
      eventSource.close();
    };
  }, [jobId]);

  // Handle incoming findings
  const handleFinding = useCallback((data: any) => {
    const newFinding: Finding = {
      id: `finding-${Date.now()}-${Math.random().toString(36).slice(2)}`,
      type: data.type,
      message: data.message || getDefaultMessage(data),
      timestamp: new Date(),
      data: data.data
    };

    setFindings(prev => [...prev, newFinding]);

    switch (data.type) {
      case 'logo':
        setLogo(typeof data.data === 'string' ? data.data : data.data?.url || data.data);
        setIsRevealed(true);
        break;
        
      case 'color':
      case 'colors':
        setColors(prev => {
          const colorData = data.data;
          // Handle {colors: [...]} or single string
          const newColors = Array.isArray(colorData) ? colorData
            : colorData?.colors ? colorData.colors
            : typeof colorData === 'string' ? [colorData]
            : prev;
          const merged = [...new Set([...prev, ...newColors])].slice(0, 6);
          return merged;
        });
        break;
        
      case 'company_name':
        setCompanyName(typeof data.data === 'string' ? data.data : data.data?.name || data.data);
        break;
        
      case 'product':
        setProducts(prev => [...prev, {
          id: `product-${Date.now()}-${Math.random().toString(36).slice(2)}`,
          title: data.data.title,
          price: data.data.price,
          image: data.data.image,
          url: data.data.url
        }]);
        break;
        
      case 'page':
        setPagesDiscovered(prev => prev + 1);
        setCurrentUrl(data.data?.url || data.data);
        break;
        
      case 'progress':
        setProgress(data.data || data.progress || 0);
        break;
        
      case 'task':
        setTasks(prev => [...prev, {
          id: `task-${Date.now()}-${Math.random().toString(36).slice(2)}`,
          title: data.data.title,
          department: data.data.department,
          priority: data.data.priority || 'medium',
          createdAt: new Date()
        }]);
        break;
        
      default:
        // Handle social, tech, etc. through findings
        break;
    }
  }, []);

  // Default messages for finding types
  const getDefaultMessage = (data: any): string => {
    const d = data.data;
    const str = (v: any) => typeof v === 'string' ? v : typeof v === 'object' ? JSON.stringify(v) : String(v || '');
    const messages: Record<string, string> = {
      logo: 'Found company logo',
      color: `Detected brand colors`,
      colors: `Detected brand colors: ${d?.colors?.join(', ') || str(d)}`,
      company_name: `Found company: ${d?.name || str(d)}`,
      product: `Found product: ${d?.title || 'New product'}`,
      page: `Crawling: ${d?.url || str(d)}`,
      instagram: 'Found Instagram link',
      facebook: 'Found Facebook page',
      twitter: 'Found Twitter/X profile',
      linkedin: 'Found LinkedIn page',
      youtube: 'Found YouTube channel',
      shopify: 'Detected Shopify platform',
      woocommerce: 'Detected WooCommerce',
      tech: `Detected: ${d?.name || str(d)}`,
      email: `Found contact email`,
      phone: 'Found phone number',
      address: 'Found business address',
      social: `Found social profile: ${d?.platform || str(d)}`,
      description: `Found company description`,
      contact: `Found contact info`,
    };
    return messages[data.type] || `Discovered: ${data.type}`;
  };

  // Handle approval
  const handleApprove = async () => {
    setIsApproving(true);
    
    try {
      await fetch(`${API_BASE}/onboarding/crawl/${jobId}/approve`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
      });
      
      if (onComplete) {
        onComplete({
          jobId: jobId!,
          companyName,
          logo,
          colors,
          products,
          findings,
          tasks
        });
      }
    } catch (err) {
      console.error('Approval failed:', err);
      setIsApproving(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 bg-[#0a0a0a] z-50 overflow-hidden"
    >
      {/* Close button */}
      {onClose && (
        <button
          onClick={onClose}
          className="absolute top-4 right-4 z-50 p-2 rounded-full bg-white/5 hover:bg-white/10 text-white/50 hover:text-white transition-colors"
        >
          <X className="w-5 h-5" />
        </button>
      )}

      {/* Main Layout */}
      <div className="h-full flex flex-col">
        {/* Top: Progress Bar */}
        <CrawlProgress
          currentUrl={currentUrl}
          pagesDiscovered={pagesDiscovered}
          progress={progress}
          isActive={status === 'crawling'}
        />

        {/* Main Content Area */}
        <div className="flex-1 flex overflow-hidden">
          {/* Left Side: Brand + Products + Findings */}
          <div className="flex-1 flex flex-col p-6 overflow-hidden">
            {/* Brand Reveal */}
            <div className="mb-6">
              <BrandReveal
                logo={logo}
                colors={colors}
                companyName={companyName}
                isRevealed={isRevealed}
              />
            </div>

            {/* Products Grid */}
            <div className="flex-1 overflow-y-auto mb-6">
              <ProductGrid products={products} maxDisplay={12} />
            </div>

            {/* Findings Feed */}
            <div className="flex-shrink-0">
              <FindingsFeed findings={findings} maxDisplay={5} />
            </div>
          </div>

          {/* Right Sidebar: Tasks */}
          <div className="w-80 border-l border-white/10 p-4 overflow-hidden flex flex-col">
            <TaskCreationFeed tasks={tasks} />
          </div>
        </div>
      </div>

      {/* Approval Gate (fixed at bottom when ready) */}
      <ApprovalGate
        companyName={companyName}
        stats={{
          products: products.length,
          colors: colors.length,
          tasks: tasks.length,
          findings: findings.length
        }}
        isReady={isReady}
        onApprove={handleApprove}
        isApproving={isApproving}
      />

      {/* Error State */}
      <AnimatePresence>
        {error && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="fixed inset-0 flex items-center justify-center bg-black/80 z-50"
          >
            <div className="bg-red-900/30 border border-red-500/30 rounded-lg p-6 max-w-md text-center">
              <h3 className="text-red-400 font-semibold mb-2">Crawl Error</h3>
              <p className="text-white/70 mb-4">{error}</p>
              <button
                onClick={onClose}
                className="px-4 py-2 bg-red-500/20 hover:bg-red-500/30 border border-red-500/30 rounded text-red-400 transition-colors"
              >
                Close
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default CrawlTheater;
