// ProductGrid.tsx — Products appearing in animated grid

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Package, DollarSign, Image as ImageIcon } from 'lucide-react';

export interface Product {
  id: string;
  title: string;
  price?: string;
  image?: string;
  url?: string;
}

interface ProductGridProps {
  products: Product[];
  maxDisplay?: number;
}

export const ProductGrid: React.FC<ProductGridProps> = ({
  products,
  maxDisplay = 12
}) => {
  const displayProducts = products.slice(0, maxDisplay);
  const hiddenCount = Math.max(0, products.length - maxDisplay);

  return (
    <div className="relative">
      {/* Header with count badge */}
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-medium text-white/60 flex items-center gap-2">
          <Package className="w-4 h-4" />
          Products
        </h3>
        <AnimatePresence mode="wait">
          {products.length > 0 && (
            <motion.div
              key={products.length}
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              className="px-3 py-1 bg-emerald-500/20 border border-emerald-500/30 rounded-full text-emerald-400 text-sm font-medium"
            >
              {products.length} products found
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Product Grid */}
      <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-3">
        <AnimatePresence mode="popLayout">
          {displayProducts.map((product, index) => (
            <motion.div
              key={product.id}
              layout
              initial={{ opacity: 0, scale: 0.8, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.8 }}
              transition={{
                delay: index * 0.05,
                type: 'spring',
                stiffness: 300,
                damping: 25
              }}
              className="group relative bg-white/5 rounded-lg overflow-hidden border border-white/10 hover:border-white/20 transition-all hover:bg-white/10 cursor-pointer"
            >
              {/* Product Image */}
              <div className="aspect-square relative overflow-hidden bg-white/5">
                {product.image ? (
                  <img
                    src={product.image}
                    alt={product.title}
                    className="w-full h-full object-cover transition-transform group-hover:scale-105"
                    loading="lazy"
                    onError={(e) => {
                      (e.target as HTMLImageElement).style.display = 'none';
                    }}
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <ImageIcon className="w-8 h-8 text-white/20" />
                  </div>
                )}
                
                {/* Shine effect on new items */}
                <motion.div
                  className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full"
                  animate={{ translateX: ['100%', '-100%'] }}
                  transition={{ duration: 1, delay: index * 0.05 }}
                />
              </div>

              {/* Product Info */}
              <div className="p-2">
                <p className="text-xs text-white/80 truncate" title={product.title}>
                  {product.title}
                </p>
                {product.price && (
                  <p className="text-xs text-emerald-400 flex items-center gap-1 mt-1">
                    <DollarSign className="w-3 h-3" />
                    {product.price}
                  </p>
                )}
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {/* "And more" card */}
        {hiddenCount > 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="aspect-square bg-white/5 rounded-lg border border-dashed border-white/20 flex items-center justify-center"
          >
            <div className="text-center">
              <p className="text-2xl font-bold text-white/40">+{hiddenCount}</p>
              <p className="text-xs text-white/30">more</p>
            </div>
          </motion.div>
        )}
      </div>

      {/* Empty state */}
      {products.length === 0 && (
        <div className="text-center py-8">
          <div className="inline-flex items-center gap-2 text-white/30 text-sm">
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
            >
              <Package className="w-5 h-5" />
            </motion.div>
            Scanning for products...
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductGrid;
