import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type {
  DepartmentOnboardingState,
  OnboardingProgress,
  OnboardingStepConfig,
} from '../types/onboarding';

// Import templates from our templates file
import { ONBOARDING_TEMPLATES, getOnboardingTemplate, calculateContextScore } from '../templates/onboarding-templates';

interface DepartmentOnboardingStore {
  // State for each department (keyed by departmentId)
  departments: Record<string, DepartmentOnboardingState>;
  
  // Actions
  initializeDepartment: (departmentId: string, templateId: string) => void;
  completeStep: (departmentId: string, stepId: string) => void;
  uncompleteStep: (departmentId: string, stepId: string) => void;
  skipOnboarding: (departmentId: string) => void;
  resumeOnboarding: (departmentId: string) => void;
  finishOnboarding: (departmentId: string) => void;
  getContextScore: (departmentId: string) => number;
  getProgress: (departmentId: string) => OnboardingProgress;
  isOnboardingComplete: (departmentId: string) => boolean;
  shouldShowOnboarding: (departmentId: string) => boolean;
  resetDepartment: (departmentId: string) => void;
}

export const useDepartmentOnboardingStore = create<DepartmentOnboardingStore>()(
  persist(
    (set, get) => ({
      departments: {},
      
      initializeDepartment: (departmentId: string, templateId: string) => {
        const existing = get().departments[departmentId];
        if (existing) return; // Don't reinitialize
        
        const template = getOnboardingTemplate(templateId);
        if (!template) return;
        
        // Initialize progress with all steps as false
        const progress: OnboardingProgress = {};
        template.onboardingSteps.forEach(step => {
          progress[step.id] = false;
        });
        
        set(state => ({
          departments: {
            ...state.departments,
            [departmentId]: {
              departmentId,
              templateId,
              progress,
              skipped: false,
              contextScore: 0,
            }
          }
        }));
      },
      
      completeStep: (departmentId: string, stepId: string) => {
        set(state => {
          const dept = state.departments[departmentId];
          if (!dept) return state;
          
          const newProgress = { ...dept.progress, [stepId]: true };
          const template = getOnboardingTemplate(dept.templateId);
          const contextScore = template ? calculateContextScore(newProgress, template) : 0;
          
          return {
            departments: {
              ...state.departments,
              [departmentId]: {
                ...dept,
                progress: newProgress,
                contextScore,
              }
            }
          };
        });
      },
      
      uncompleteStep: (departmentId: string, stepId: string) => {
        set(state => {
          const dept = state.departments[departmentId];
          if (!dept) return state;
          
          const newProgress = { ...dept.progress, [stepId]: false };
          const template = getOnboardingTemplate(dept.templateId);
          const contextScore = template ? calculateContextScore(newProgress, template) : 0;
          
          return {
            departments: {
              ...state.departments,
              [departmentId]: {
                ...dept,
                progress: newProgress,
                contextScore,
              }
            }
          };
        });
      },
      
      skipOnboarding: (departmentId: string) => {
        set(state => {
          const dept = state.departments[departmentId];
          if (!dept) return state;
          
          return {
            departments: {
              ...state.departments,
              [departmentId]: {
                ...dept,
                skipped: true,
                skippedAt: new Date(),
              }
            }
          };
        });
      },
      
      resumeOnboarding: (departmentId: string) => {
        set(state => {
          const dept = state.departments[departmentId];
          if (!dept) return state;
          
          return {
            departments: {
              ...state.departments,
              [departmentId]: {
                ...dept,
                skipped: false,
                skippedAt: undefined,
              }
            }
          };
        });
      },
      
      finishOnboarding: (departmentId: string) => {
        set(state => {
          const dept = state.departments[departmentId];
          if (!dept) return state;
          
          return {
            departments: {
              ...state.departments,
              [departmentId]: {
                ...dept,
                completedAt: new Date(),
              }
            }
          };
        });
      },
      
      getContextScore: (departmentId: string) => {
        const dept = get().departments[departmentId];
        return dept?.contextScore || 0;
      },
      
      getProgress: (departmentId: string) => {
        const dept = get().departments[departmentId];
        return dept?.progress || {};
      },
      
      isOnboardingComplete: (departmentId: string) => {
        const dept = get().departments[departmentId];
        if (!dept) return false;
        
        const template = getOnboardingTemplate(dept.templateId);
        if (!template) return false;
        
        // Check if all required steps are complete
        const requiredSteps = template.onboardingSteps.filter(s => s.required);
        return requiredSteps.every(step => dept.progress[step.id]);
      },
      
      shouldShowOnboarding: (departmentId: string) => {
        const dept = get().departments[departmentId];
        if (!dept) return true; // Not initialized = show onboarding
        if (dept.skipped) return false; // User skipped
        if (dept.completedAt) return false; // Already completed
        
        // Show if not all required steps are done
        return !get().isOnboardingComplete(departmentId);
      },
      
      resetDepartment: (departmentId: string) => {
        set(state => {
          const { [departmentId]: _, ...remaining } = state.departments;
          return { departments: remaining };
        });
      },
    }),
    {
      name: 'department-onboarding-storage',
    }
  )
);
