// CrawlProgress.tsx — Top progress bar showing crawl status

import React from 'react';
import { motion } from 'framer-motion';
import { Globe, FileText, Loader2 } from 'lucide-react';

interface CrawlProgressProps {
  currentUrl: string;
  pagesDiscovered: number;
  progress: number; // 0-100
  isActive: boolean;
}

export const CrawlProgress: React.FC<CrawlProgressProps> = ({
  currentUrl,
  pagesDiscovered,
  progress,
  isActive
}) => {
  return (
    <div className="w-full px-6 py-4">
      {/* Progress Bar */}
      <div className="relative h-1 bg-white/10 rounded-full overflow-hidden mb-3">
        <motion.div
          className="absolute inset-y-0 left-0 bg-gradient-to-r from-cyan-500 to-emerald-500"
          initial={{ width: 0 }}
          animate={{ width: `${progress}%` }}
          transition={{ duration: 0.5, ease: 'easeOut' }}
        />
        {isActive && (
          <motion.div
            className="absolute inset-y-0 w-32 bg-gradient-to-r from-transparent via-white/30 to-transparent"
            animate={{ x: ['-128px', '100vw'] }}
            transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
          />
        )}
      </div>

      {/* Status Row */}
      <div className="flex items-center justify-between">
        {/* Current URL */}
        <div className="flex items-center gap-2 min-w-0 flex-1">
          {isActive ? (
            <Loader2 className="w-4 h-4 text-cyan-400 animate-spin flex-shrink-0" />
          ) : (
            <Globe className="w-4 h-4 text-cyan-400 flex-shrink-0" />
          )}
          <motion.span
            key={currentUrl}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-sm text-white/70 truncate font-mono"
          >
            {currentUrl || 'Preparing crawl...'}
          </motion.span>
        </div>

        {/* Pages Count */}
        <motion.div
          className="flex items-center gap-2 text-sm text-white/50 flex-shrink-0 ml-4"
          initial={{ scale: 1 }}
          animate={{ scale: pagesDiscovered > 0 ? [1, 1.1, 1] : 1 }}
          transition={{ duration: 0.3 }}
        >
          <FileText className="w-4 h-4" />
          <span>
            <motion.span
              key={pagesDiscovered}
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-white font-medium"
            >
              {pagesDiscovered}
            </motion.span>
            {' '}pages discovered
          </span>
        </motion.div>
      </div>
    </div>
  );
};

export default CrawlProgress;
