// OnboardingPage - Entry point for Crawl Theater visual onboarding
// Allows user to enter a URL and watch their business being analyzed

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CrawlTheater } from '@/components/onboarding';
import { Globe, ArrowRight, Sparkles } from 'lucide-react';

export function OnboardingPage() {
  const navigate = useNavigate();
  const [url, setUrl] = useState('');
  const [companyName, setCompanyName] = useState('');
  const [crawlStarted, setCrawlStarted] = useState(false);
  const [jobId, setJobId] = useState<string | null>(null);

  const API_BASE = import.meta.env.VITE_API_URL || 'https://ienable-admin-app-hqtw2.ondigitalocean.app/api/v1';

  const handleStartCrawl = async () => {
    if (!url) return;

    try {
      const response = await fetch(`${API_BASE}/onboarding/crawl`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          url: url.startsWith('http') ? url : `https://${url}`,
          company_name: companyName || 'New Company'
        })
      });
      
      const data = await response.json();
      if (data.success) {
        setJobId(data.data.job_id);
        setCrawlStarted(true);
      }
    } catch (error) {
      console.error('Failed to start crawl:', error);
    }
  };

  const handleComplete = () => {
    // Navigate to company setup or dashboard
    navigate('/customers/companies');
  };

  if (crawlStarted && jobId) {
    return (
      <CrawlTheater 
        jobId={jobId} 
        onComplete={handleComplete}
      />
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-blue-500/10 mb-4">
            <Sparkles className="w-8 h-8 text-blue-400" />
          </div>
          <h1 className="text-3xl font-bold text-white mb-2">
            Let's Understand Your Business
          </h1>
          <p className="text-slate-400">
            Enter your website and watch as we analyze your brand, products, and opportunities.
          </p>
        </div>

        {/* Form */}
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">
              Company Name (optional)
            </label>
            <input
              type="text"
              value={companyName}
              onChange={(e) => setCompanyName(e.target.value)}
              placeholder="Acme Inc."
              className="w-full px-4 py-3 bg-slate-800 border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">
              Website URL
            </label>
            <div className="relative">
              <Globe className="absolute left-4 top-1/2 transform -translate-y-1/2 w-5 h-5 text-slate-500" />
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="example.com"
                className="w-full pl-12 pr-4 py-3 bg-slate-800 border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                onKeyDown={(e) => e.key === 'Enter' && handleStartCrawl()}
              />
            </div>
          </div>

          <button
            onClick={handleStartCrawl}
            disabled={!url}
            className="w-full flex items-center justify-center gap-2 px-6 py-4 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 disabled:cursor-not-allowed text-white font-semibold rounded-lg transition-colors"
          >
            Start Analysis
            <ArrowRight className="w-5 h-5" />
          </button>
        </div>

        {/* Footer */}
        <p className="text-center text-slate-500 text-sm mt-8">
          We'll extract your brand colors, products, tech stack, and more.
        </p>
      </div>
    </div>
  );
}
